import React from 'react';
import {
  Drawer,
  List,
  ListItem,
  ListItemButton,
  ListItemIcon,
  ListItemText,
  Avatar,
  Box,
  Typography,
  Divider,
  Button,
  Chip
} from '@mui/material';
import {
  Dashboard as DashboardIcon,
  Inventory as InventoryIcon,
  ShoppingCart as OrdersIcon,
  AddBox as PurchaseIcon,
  Assessment as ReportingIcon,
  Support as SupportIcon,
  Settings as SettingsIcon,
  Logout as LogoutIcon,
} from '@mui/icons-material';

import { useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

function Sidebar({ mobileOpen, handleDrawerToggle, drawerWidth }) {
  const navigate = useNavigate();
  const location = useLocation();
  const { user, logout, hasRole } = useAuth();

  const menuItems = [
    { text: 'Dashboard', icon: <DashboardIcon />, path: '/dashboard', roles: ['admin','manager','viewer'] },
    { text: 'Inventory', icon: <InventoryIcon />, path: '/dashboard/products', roles: ['admin','manager','viewer'] },
    { text: 'Orders', icon: <OrdersIcon />, path: '/dashboard/orders', roles: ['admin','manager','viewer'] },
    { text: 'Purchase', icon: <PurchaseIcon />, path: '/dashboard/purchase', roles: ['admin','manager'] },
    { text: 'Reporting', icon: <ReportingIcon />, path: '/dashboard/reporting', roles: ['admin','manager','viewer'] },
    { text: 'Support', icon: <SupportIcon />, path: '/dashboard/support', roles: ['admin','manager','viewer'] },
    { text: 'Settings', icon: <SettingsIcon />, path: '/dashboard/settings', roles: ['admin'] },
  ];

  const visibleMenuItems = menuItems.filter(item =>
    item.roles.includes(user?.role || 'viewer')
  );

  const handleLogout = async () => {
    if (window.confirm("Are you sure you want to logout?")) {
      await logout();
    }
  };

  const getRoleColor = (role) => {
    switch (role) {
      case 'admin': return 'error';
      case 'manager': return 'warning';
      case 'viewer': return 'info';
      default: return 'default';
    }
  };

  const getRoleIcon = (role) => {
    switch (role) {
      case 'admin': return '👑';
      case 'manager': return '👔';
      case 'viewer': return '👀';
      default: return '👤';
    }
  };

  const drawer = (
    <Box sx={{ height: "100%", display: "flex", flexDirection: "column", overflowY: 'auto' }}>
      <Box sx={{ flexGrow: 1 }}>
        {/* PROFILE */}
        <Box sx={{
          p: 3,
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          backgroundColor: "rgba(255,255,255,0.1)"
        }}>
          <Avatar sx={{ width: 80, height: 80, mb: 2, fontSize: "2rem" }}>
            {user?.name ? user.name[0].toUpperCase() : "U"}
          </Avatar>

          <Typography variant="h6" sx={{ color: "white" }}>
            {user?.name}
          </Typography>
          <Typography variant="caption" sx={{ color: "#ddd" }}>
            {user?.email}
          </Typography>

          <Chip
            label={`${getRoleIcon(user?.role)} ${user?.role}`}
            color={getRoleColor(user?.role)}
            sx={{ mt: 1, color: "white", textTransform: "capitalize" }}
          />
        </Box>

        <Divider sx={{ backgroundColor: "rgba(255,255,255,0.2)" }} />

        {/* MENU */}
        <List sx={{ px: 1 }}>
          {visibleMenuItems.map((item) => (
            <ListItem key={item.text} disablePadding sx={{ mb: 0.5 }}>
              <ListItemButton
                onClick={() => {
                  navigate(item.path);
                  if (mobileOpen) handleDrawerToggle();
                }}
                selected={location.pathname === item.path}
                sx={{
                  borderRadius: "8px",
                  "&.Mui-selected": {
                    backgroundColor: "rgba(255,255,255,0.2)"
                  }
                }}
              >
                <ListItemIcon sx={{ color: "white" }}>
                  {item.icon}
                </ListItemIcon>
                <ListItemText
                  primary={item.text}
                  sx={{ color: "white" }}
                />
              </ListItemButton>
            </ListItem>
          ))}
        </List>
      </Box>

      {/* LOGOUT */}
      <Box sx={{ p: 2 }}>
        <Button
          fullWidth
          variant="text"
          startIcon={<LogoutIcon />}
          onClick={handleLogout}
          sx={{ color: "white" }}
        >
          Logout
        </Button>
      </Box>
    </Box>
  );

  return (
    <>
      {/* MOBILE SIDEBAR */}
      <Drawer
        variant="temporary"
        open={mobileOpen}
        onClose={handleDrawerToggle}
        sx={{
          display: { xs: "block", sm: "none" },
          "& .MuiDrawer-paper": {
            width: drawerWidth,
            backgroundColor: "#4A6B7C"
          }
        }}
      >
        {drawer}
      </Drawer>

      {/* DESKTOP SIDEBAR */}
      <Drawer
        variant="permanent"
        sx={{
          display: { xs: "none", sm: "block" },
          "& .MuiDrawer-paper": {
            width: drawerWidth,
            backgroundColor: "#4A6B7C",
            marginTop: "64px"
          }
        }}
        open
      >
        {drawer}
      </Drawer>
    </>
  );
}

export default Sidebar;

import React, { createContext, useState, useContext, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { setAccessToken } from '../services/api';


const AuthContext = createContext({});
let accessToken = null; 

axios.defaults.baseURL = import.meta.env.VITE_API_URL;
axios.defaults.withCredentials = true; 


axios.interceptors.response.use(
    (res) => res,
    async (err) => {
      const original = err.config;

      if (original.url.includes("/api/auth/refresh")) {
        console.warn("Refresh request failed.");
        return Promise.reject(err);
      }

      if (err.response?.status === 401 && !original._retry) {
        original._retry = true;

        try {
          const refreshed = await axios.post( import.meta.env.VITE_API_URL + "/api/auth/refresh", {}, { withCredentials: true });

          const newAccessToken = refreshed.data.accessToken;
          setAccessToken(newAccessToken);

          axios.defaults.headers.common["Authorization"] = `Bearer ${newAccessToken}`;
          original.headers["Authorization"] = `Bearer ${newAccessToken}`;

          return axios(original);
        } catch (refreshErr) {
            console.error('Refresh failed:', refreshErr);
            window.location.href = "/login";
            return Promise.reject(refreshErr);
        }
      }

      return Promise.reject(err);
    }
  );
  export const AuthProvider = ({ children }) => {
    const navigate = useNavigate();
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);


    const login = async (email, password) => {
        try {
            setError(null)
            const res = await axios.post("/api/auth/login", { email, password });
            const { accessToken, user: userData } = res.data;


            setAccessToken(accessToken);

            axios.defaults.headers.common["Authorization"] = `Bearer ${accessToken}`;

            localStorage.setItem("user", JSON.stringify(userData));
            setUser(userData);
            return { success: true, data: userData };

        } catch (err) {
            const message = err.response?.data?.message || 'Login failed';
            setError(message);
            return { success: false, error: message };
        }
    };
    const register = async (formData) => {
        try {
            setError(null);
            const response = await axios.post('/api/auth/register', formData);
            return { success: true, data: response.data };

        } catch (err) {
            const message = err.response?.data?.message || 'Registration failed';
            setError(message);
            return { success: false, error: message };
        }
    };
    const logout = async () => {
        try {
            await axios.post("/api/auth/logout", {}, { withCredentials: true });
        } catch (error) {
            console.error('Logout error:', error);
        }
        setAccessToken(null);
        delete axios.defaults.headers.common["Authorization"];

        localStorage.removeItem("user");
        setUser(null);
        navigate("/login");

    };
    const forgotPassword = async (email) => {
        try {
            setError(null);
            const response = await axios.post('/api/password/request', { email });
            return { success: true, data: response.data };
        } catch (err) {
            const message = err.response?.data?.message || "Failed to send email";
            setError(message);
            return { success: false, error: message };

        }
    };

    const resetPassword = async (userId, token, newPassword) => {
        try {
            setError(null);
            const response = await axios.post('/api/password/confirm', {
                userId,
                token,
                newPassword
            });
            return { success: true, data: response.data };
        } catch (err) {
            const message = err.response?.data?.message || "Failed to reset password";
            setError(message);
            return { success: false, error: message };
        }
    };
    const updateProfile = async (updates) => {
        try {
            const response = await axios.put('/api/auth/profile', updates);
            const updatedUser = response.data.user;

            setUser(updatedUser);
            localStorage.setItem('user', JSON.stringify(updatedUser));

            return { success: true, data: updatedUser };
        } catch (err) {
            const message = err.response?.data?.message || 'Failed to update profile';
            return { success: false, error: message };
        }
    };
    const hasRole = (roles) => {
        if (!user) return false;
        if (typeof roles === 'string') return user.role === roles;
        if (Array.isArray(roles)) return roles.includes(user.role);
        return false;
    };

    const canAccess = (requiredRoles) => {
        if (!user) return false;
        if (user.role === 'admin') return true; 
        return hasRole(requiredRoles);
    };


    // const checkAuth = async () => {
    //     const savedUser = localStorage.getItem("user");
    //     if (!savedUser) {
    //       setLoading(false);
    //       return;
    //     }

    //     try {
    //         const refreshed = await axios.post("/api/auth/refresh", {}, { 
    //             withCredentials: true 
    //         });

    //         const { accessToken } = refreshed.data;

    //         setAccessToken(accessToken);
    //         axios.defaults.headers.common["Authorization"] = `Bearer ${accessToken}`;

    //         setUser(JSON.parse(savedUser));
    //     } catch (error) {
    //         console.error('Auth check failed:', error);
    //         localStorage.removeItem("user");
    //         setUser(null);
    //     }

    //     setLoading(false);
    //   };
    const checkAuth = async () => {
        const savedUser = localStorage.getItem("user");
        if (savedUser) {
            setUser(JSON.parse(savedUser));
        }
        setLoading(false);
    };


      useEffect(() => {
        checkAuth();
      }, []);

    //   useEffect(() => {
    //     if (!user) return;

    //     const refreshInterval = setInterval(async () => {
    //         try {
    //             const refreshed = await axios.post("/api/auth/refresh", {}, { 
    //                 withCredentials: true 
    //             });

    //             const { accessToken } = refreshed.data;
    //             setAccessToken(accessToken);
    //             axios.defaults.headers.common["Authorization"] = `Bearer ${accessToken}`;

    //             console.log('Token refreshed successfully');
    //         } catch (error) {
    //             console.error('Auto-refresh failed:', error);
    //             logout();
    //         }
    //     }, 14 * 60 * 1000); 

    //     return () => clearInterval(refreshInterval);
    // }, [user]);


    const value = {
        user,
        loading,
        login,
        register,
        logout,
        forgotPassword,
        resetPassword,
        updateProfile,
        hasRole,
        canAccess,
        isAuthenticated: !!user,
    };

    return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;

};

// Move useAuth outside of AuthProvider
export const useAuth = () => {
    const context = useContext(AuthContext);
    if (!context) {
        throw new Error('useAuth must be used within an AuthProvider');
    }
    return context;
};

export default AuthContext;

import React, { createContext, useState, useEffect } from 'react';
import { useContext } from 'react';
const NotificationContext = createContext();

export const useNotifications = () => {
  const context = useContext(NotificationContext);
  if (!context) {
      throw new Error('useNotification must be used within a NotificationProvider');
  }
  return context;
};
export function NotificationProvider({ children }) {
    const [notifications, setNotifications] = useState(() => {
        // Load from local storage wen app starts
        const saved = localStorage.getItem('notifications');
        return saved ? JSON.parse(saved) : [];
    })


  const [unreadCount, setUnreadCount] = useState(0);

   // Save to localStorage whenever notifications change
   useEffect(() => {
    localStorage.setItem('notifications', JSON.stringify(notifications));
    // Update unread cout
    const unread = notifications.filter(n => !n.read).length;
    setUnreadCount(unread);
  }, [notifications]);


  const addNotification = (message, type = 'info') => {
    const newNotification = {
      id: Date.now(), 
      message,
      type, 
      timestamp: new Date().toISOString(),
      read: false
    };


    setNotifications(prev => [newNotification, ...prev]);
  };
  // Mark one notification as read
  const markAsRead = (id) => {
    setNotifications(prev =>
      prev.map(notif => 
        notif.id === id 
          ? { ...notif, read: true } 
          : notif 
      )
    );
  };
  // Mark all as read
  const markAllAsRead = () => {
    setNotifications(prev =>
      prev.map(notif => ({ ...notif, read: true }))
    );
  };
  // Clear all notifications
  const clearAll = () => {
    setNotifications([]);
  };

  // Provide these to all child components
  return (
    <NotificationContext.Provider value={{
      notifications,
      unreadCount,
      addNotification,
      markAsRead,
      markAllAsRead,
      clearAll,
    }}>
      {children}
    </NotificationContext.Provider>
  );
}

import React, { createContext, useState, useMemo, useContext } from "react";
import { createTheme, ThemeProvider } from "@mui/material/styles";
import CssBaseline from "@mui/material/CssBaseline";

const ThemeContext = createContext();

export const useThemeMode = () => useContext(ThemeContext);

export function ThemeModeProvider({ children }) {
  const [mode, setMode] = useState("light");

  const toggleMode = () => {
    setMode((prev) => (prev === "light" ? "dark" : "light"));
  };

  const theme = useMemo(
    () =>
      createTheme({
        palette: {
          mode,
          ...(mode === "light"
            ? {
                background: { default: "#F5F7FA" },
                primary: { main: "#4A6B7C" },
              }
            : {
                background: { default: "#121212", paper: "#1E1E1E" },
                primary: { main: "#90caf9" },
              }),
        },
        typography: {
          fontFamily: "Inter, Roboto, sans-serif",
        },
      }),
    [mode]
  );

  return (
    <ThemeContext.Provider value={{ mode, toggleMode, theme }}>
      <ThemeProvider theme={theme}>
        <CssBaseline />
        {children}
      </ThemeProvider>
    </ThemeContext.Provider>
  );
}

import React, { useState } from 'react';
import { showSuccess, showError } from '../utils/toast';

import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Grid,
  MenuItem,
  Snackbar,
  Alert,
} from '@mui/material';
import { useNavigate } from 'react-router-dom';
import { productAPI } from '../services/api';

const categories = ['Electronics', 'Furniture', 'Clothing', 'Food', 'Books'];

function AddProduct() {
  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    name: '',
    category: '',
    quantity: '',
    price: '',
  });

  // Snackbar + Error states
  const [openSnackbar, setOpenSnackbar] = useState(false);
  const [snackbarMessage, setSnackbarMessage] = useState('');
  const [snackbarSeverity, setSnackbarSeverity] = useState('success');
  const [loading, setLoading] = useState(false);

  // Handle form field updates
  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  // Handle form submit
  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.name || !formData.category || !formData.quantity || !formData.price) {
      setSnackbarMessage('Please fill all fields.');
      setSnackbarSeverity('error');
      setOpenSnackbar(true);
      return;
    }

    try {
      setLoading(true);
      await productAPI.create({
        ...formData,
        quantity: parseInt(formData.quantity),
        price: parseFloat(formData.price),
      });

      showSuccess('Product added successfully!');
      setTimeout(() => navigate('/products'), 800);
    } catch (error) {
      showError('Failed to add product.');

    } finally {
      setLoading(false);
    }
  };

  return (
    <Box>
      <Typography variant="h4" sx={{ mb: 3 }}>
        Add New Product
      </Typography>

      <Paper sx={{ p: 4, maxWidth: 600 }}>
        <form onSubmit={handleSubmit}>
          <Grid container spacing={3}>
            <Grid item xs={12}>
              <TextField
                fullWidth
                label="Product Name"
                name="name"
                value={formData.name}
                onChange={handleChange}
                required
              />
            </Grid>

            <Grid item xs={12}>
              <TextField
                fullWidth
                select
                label="Category"
                name="category"
                value={formData.category}
                onChange={handleChange}
                required
              >
                {categories.map((option) => (
                  <MenuItem key={option} value={option}>
                    {option}
                  </MenuItem>
                ))}
              </TextField>
            </Grid>

            <Grid item xs={12} sm={6}>
              <TextField
                fullWidth
                label="Quantity"
                name="quantity"
                type="number"
                value={formData.quantity}
                onChange={handleChange}
                required
              />
            </Grid>

            <Grid item xs={12} sm={6}>/api/products

              <TextField
                fullWidth
                label="Price"
                name="price"
                type="number"
                value={formData.price}
                onChange={handleChange}
                required
              />
            </Grid>

            <Grid item xs={12}>
              <Box sx={{ display: 'flex', gap: 2, justifyContent: 'flex-end' }}>
                <Button
                  variant="outlined"
                  onClick={() => navigate('/products')}
                  disabled={loading}
                >
                  Cancel
                </Button>
                <Button
                  type="submit"
                  variant="contained"
                  sx={{ backgroundColor: '#4A6B7C' }}
                  disabled={loading}
                >
                  {loading ? 'Adding...' : 'Add Product'}
                </Button>
              </Box>
            </Grid>
          </Grid>
        </form>
      </Paper>
    </Box>
  );
}

export default AddProduct;

import React, { useState, useEffect } from 'react';
import { motion } from "framer-motion";
import {
  Box,
  Grid,
  Typography,
  Paper,
  List,
  ListItem,
  ListItemText,
  ListItemIcon,
} from '@mui/material';
import {
  Inventory2Outlined,
  ShoppingCartOutlined,
  TrendingUpOutlined,
  WarningAmberOutlined,
  Add as AddIcon,
  Edit as EditIcon,
  Warning as WarningIcon,
  AttachMoney as AttachMoneyIcon,
} from '@mui/icons-material';
import { productAPI } from '../services/api';
import StatCard from '../components/Dashboard/StatCard';
import InventoryChart from '../components/Dashboard/InventoryChart';
import TopProducts from '../components/Dashboard/TopProducts';
import ExpenseChart from '../components/Dashboard/ExpenseChart';
import { showError } from '../utils/toast';


function Dashboard() {
  const [stats, setStats] = useState({
    totalProducts: 0,
    totalValue: 0,
    totalOrders: 0,
    totalStock: 0,
    outOfStock: 0,
  });
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [exchangeRates, setExchangeRates] = useState(null);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  // useEffect for the external API exchange rates
  useEffect(() => {
    fetch('https://api.exchangerate-api.com/v4/latest/USD')
      .then(res => res.json())
      .then(data => {
        const currencies = ['EUR', 'GBP', 'JPY', 'AUD', 'CAD', 'INR'];
        const rates = currencies.map(currency => ({
          currency: currency,
          rate: data.rates[currency],
          date: data.date
        }));
        setExchangeRates(rates);
      })
      .catch(error => console.error('Error fetching exchange rates:', error));
  }, []);

  const fetchDashboardData = async () => {
    try {
      const response = await productAPI.getAll();
      const productData = response.data.data;

      const statistics = {
        totalProducts: productData.length,
        totalOrders: 200,
        totalStock: productData.reduce((sum, product) => sum + product.quantity, 0),
        outOfStock: productData.filter(product => product.quantity === 0).length
      };

      setStats(statistics);
      setProducts(productData);
      setLoading(false);
    } catch (error) {
      showError("Error fetching dashboard data:", error);
      setLoading(false);
    }
  };
  const totalValue = products.reduce((sum, p) => sum + (p.quantity * p.price), 0);

  const statCards = [
    {
      title: 'Total Value',
      value: `$${totalValue.toLocaleString()}`,
      icon: <AttachMoneyIcon />,
      color: '#9C27B0',
      bgColor: '#F3E5F5',
    },

    {
      title: 'Total Products',
      value: stats.totalProducts,
      icon: <Inventory2Outlined />,
      color: '#4CAF50',
      bgColor: '#E8F5E9',
    },
    {
      title: 'Orders',
      value: stats.totalOrders.toLocaleString(),
      icon: <ShoppingCartOutlined />,
      color: '#2196F3',
      bgColor: '#E3F2FD',
    },
    {
      title: 'Total Stock',
      value: stats.totalStock.toLocaleString(),
      icon: <TrendingUpOutlined />,
      color: '#00BCD4',
      bgColor: '#E0F7FA',
    },
    {
      title: 'Out of Stock',
      value: stats.outOfStock,
      icon: <WarningAmberOutlined />,
      color: '#FF9800',
      bgColor: '#FFF3E0',
      alert: true,
    },
  ];

  return (
    <Box
        component={motion.div}
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, y: -10 }}
        transition={{ duration: 0.4 }}

    >
      {/* Page Title */}
      <Typography variant="h4" sx={{ mb: 4, color: 'text.primary' }}>
        Dashboard Overview
      </Typography>

      {/* Stat Cards */}
      <Grid container spacing={3} sx={{ mb: 4 }}>
        {statCards.map((card, index) => (
          <Grid item xs={12} sm={6} md={3} key={index}>
            <StatCard {...card} />
          </Grid>
        ))}
      </Grid>

      {/* Charts and Tables */}
      <Grid container spacing={3}>
        {/* Left Column */}
        <Grid item xs={12} md={8}>
          {/* User Stats & Inventory Values Row */}
          <Grid container spacing={3} sx={{ mb: 3 }}>
            <Grid item xs={12} sm={6}>
              <Paper sx={{ p: 2, height: '200px' }}>
                <Typography variant="h6" gutterBottom>
                  No of Users
                </Typography>
                <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '140px' }}>
                  <Typography variant="h2" color="primary">
                    583K
                  </Typography>
                </Box>
                <Typography variant="h6" color="text.secondary" align="center">
                  Total Customers
                </Typography>
              </Paper>
            </Grid>

            <Grid item xs={12} sm={6}>
              <Paper sx={{ p: 2, height: '200px' }}>
                <InventoryChart products={products} />
              </Paper>
            </Grid>
          </Grid>

          {/* Expense vs Profit Chart */}
          <Paper sx={{ p: 3 }}>
            <ExpenseChart />
          </Paper>
        </Grid>

        {/* Right Column - Top Products */}
        <Grid item xs={12} md={4}>
          <Paper sx={{ p: 2, height: '100%' }}>
            <TopProducts products={products} />
          </Paper>
        </Grid>
      </Grid>

      <Grid container spacing={3} sx={{ mt: 2 }}>
        {/* Currency Exchange Rates API*/}
        <Grid item xs={12} md={4}>
